SELECT id, gateway_id, tool_id, tool_name, tool_type, tool_description, http_url, http_method, http_headers, timeout, retry_times, status, create_time, update_time
FROM mcp_protocol_registry
WHERE id = #{id}

SELECT id, gateway_id, tool_id, tool_name, tool_type, tool_description, http_url, http_method, http_headers, timeout, retry_times, status, create_time, update_time
FROM mcp_protocol_registry
WHERE tool_id = #{toolId}

SELECT id, gateway_id, tool_id, tool_name, tool_type, tool_description, http_url, http_method, http_headers, timeout, retry_times, status, create_time, update_time
FROM mcp_protocol_registry
WHERE gateway_id = #{gatewayId} AND tool_name = #{toolName}
